  {id: 71, tipo: "om", pregunta: "¿Qué comando redistribuye una ruta por defecto hacia OSPF?", opciones: ["redistribute static", "default-information originate", "network 0.0.0.0"], correcta: 1, justificacion: "Inyecta la ruta 0.0.0.0/0 en el dominio OSPF."},
  {id: 72, tipo: "escenario", pregunta: "Se configura hello-interval 5 en un router y se deja el default (10) en el vecino. ¿Qué ocurre?", opciones: ["Convergen más rápido", "La adyacencia no se forma", "Se forma pero con errores"], correcta: 1, justificacion: "Los temporizadores deben ser idénticos en ambos extremos."},
  {id: 73, tipo: "completar", pregunta: "Si no se configura manualmente, OSPF elige su Router ID basándose en la IP más alta de sus interfaces ______.", opciones: ["Seriales", "Loopback", "VLANs"], correcta: 1, justificacion: "Prioridad: 1. Comando manual, 2. Loopback más alta, 3. Física más alta."},
  {id: 74, tipo: "vf", pregunta: "La redistribución de rutas entre OSPF y RIP debe configurarse manualmente y puede generar bucles.", correcta: true, justificacion: "Los protocolos no comparten rutas nativamente."},
  {id: 75, tipo: "om", pregunta: "¿Qué tipo de LSA inunda el Área 0 con información de redes externas?", opciones: ["Tipo 1", "Tipo 2", "Tipo 5"], correcta: 2, justificacion: "Tipo 5 son AS-External LSAs generadas por el ASBR."},
  {id: 76, tipo: "sm", pregunta: "¿Cuáles son métricas válidas para determinar una ruta más eficiente?", opciones: ["Ancho de banda", "Retardo (Delay)", "Cantidad de puertos", "Confiabilidad"], correcta: [0, 1, 3], justificacion: "La cantidad de puertos no es una métrica de calidad."},
  {id: 77, tipo: "vf", pregunta: "Una ruta estática tiene una Distancia Administrativa de 1, preferible sobre OSPF (110).", correcta: true, justificacion: "AD 1 (Estática) < AD 110 (OSPF)."},
  {id: 78, tipo: "om", pregunta: "¿Qué comando muestra la base de datos de estado de enlace en OSPF?", opciones: ["show ip ospf database", "show ip route", "show ip ospf neighbor"], correcta: 0, justificacion: "Muestra todos los LSAs almacenados en la LSDB."},
  {id: 79, tipo: "escenario", pregunta: "Un router aprende la red 10.0.0.0/8 por EIGRP (AD 90) y por OSPF (AD 110). ¿Cuál instala?", opciones: ["OSPF", "EIGRP", "Ambas (Balanceo)"], correcta: 1, justificacion: "Gana la menor Distancia Administrativa (EIGRP)."},
  {id: 80, tipo: "vf", pregunta: "IGP (como OSPF) se usa dentro de un Sistema Autónomo, mientras que EGP (BGP) se usa entre Sistemas Autónomos.", correcta: true, justificacion: "Definición clásica de IGP vs EGP."},
  {id: 81, tipo: "om", pregunta: "En el diseño jerárquico, ¿qué capa actúa como límite entre Capa 2 y Capa 3?", opciones: ["Acceso", "Distribución", "Núcleo"], correcta: 1, justificacion: "Distribución agrega y aplica políticas; Núcleo solo conmuta rápido."},
  {id: 82, tipo: "vf", pregunta: "Un diseño de 'Núcleo Contraído' fusiona las capas de Distribución y Núcleo en un solo dispositivo.", correcta: true, justificacion: "Reduce costos manteniendo la lógica jerárquica."},
  {id: 83, tipo: "om", pregunta: "¿Qué protocolo FHRP es estándar abierto (IEEE)?", opciones: ["HSRP", "VRRP", "GLBP"], correcta: 1, justificacion: "VRRP es abierto; HSRP y GLBP son propietarios de Cisco."},
  {id: 84, tipo: "sm", pregunta: "¿Qué roles utiliza GLBP para lograr balanceo de carga real?", opciones: ["Active / Standby", "AVG", "AVF"], correcta: [1, 2], justificacion: "GLBP usa AVG para asignar MACs y AVFs para reenviar tráfico."},
  {id: 85, tipo: "completar", pregunta: "En HSRP, el comando ______ permite que el router con mayor prioridad recupere su rol de Activo.", opciones: ["standby preempt", "standby track", "standby active"], correcta: 0, justificacion: "Sin preempt, el router de respaldo se queda como Activo indefinidamente."},
  {id: 86, tipo: "om", pregunta: "¿Qué tecnología agrupa múltiples enlaces físicos en uno lógico para evitar que STP los bloquee?", opciones: ["Trunking", "EtherChannel", "Port Mirroring"], correcta: 1, justificacion: "EtherChannel (LACP/PAgP) crea un Port-Channel lógico."},
  {id: 87, tipo: "vf", pregunta: "Para que se forme un EtherChannel con LACP, ambos lados deben estar en modo passive.", correcta: false, justificacion: "passive + passive nunca forma canal. Al menos uno debe ser active."},
  {id: 88, tipo: "escenario", pregunta: "La empresa quiere minimizar vulnerabilidades sin afectar servicios críticos. ¿Qué medida es correcta?", opciones: ["Aplicar parches inmediatos en producción", "Probar actualizaciones en laboratorio primero", "Ignorar updates menores"], correcta: 1, justificacion: "Las pruebas previas evitan fallos en servicios críticos."},
  {id: 89, tipo: "sm", pregunta: "Seleccione controles correctos para una política de auditoría:", opciones: ["Alertas por cada evento menor", "Revisar logs y correlacionar eventos", "Alertas automatizadas sobre actividad sospechosa"], correcta: [1, 2], justificacion: "Alertar por todo genera 'fatiga de alertas' y ruido."},
  {id: 90, tipo: "om", pregunta: "¿Qué principio de seguridad garantiza que los datos no sean alterados?", opciones: ["Confidencialidad", "Integridad", "Disponibilidad"], correcta: 1, justificacion: "La Tríada CIA: Confidencialidad, Integridad, Disponibilidad."},
  {id: 91, tipo: "vf", pregunta: "Un IPS solo monitorea y alerta, mientras que un IDS bloquea automáticamente.", correcta: false, justificacion: "Es al revés. IDS = Detección. IPS = Prevención (Bloquea)."},
  {id: 92, tipo: "om", pregunta: "¿Qué tipo de Hypervisor se instala directamente sobre el hardware (Bare-Metal)?", opciones: ["Tipo 1", "Tipo 2", "Contenedor"], correcta: 0, justificacion: "Tipo 1 (ESXi, Proxmox). Tipo 2 (VirtualBox) va sobre un SO."},
  {id: 93, tipo: "escenario", pregunta: "Una VM conectada a NAT y Host-Only no puede comunicarse con otra VM en la misma red Host-Only. ¿Causas probables?", opciones: ["NIC Host-Only desactivada", "Firewall del host bloqueando", "NAT bloquea todo"], correcta: [0, 1], justificacion: "NAT no afecta la red Host-Only."},
  {id: 94, tipo: "completar", pregunta: "______ es una tecnología de virtualización a nivel de SO que comparte el Kernel del host.", opciones: ["VMware", "Docker (Contenedores)", "Hyper-V"], correcta: 1, justificacion: "Los contenedores no virtualizan hardware, solo el SO."},
  {id: 95, tipo: "om", pregunta: "En Windows Server, ¿qué se necesita por cada usuario o dispositivo que accede a los servicios?", opciones: ["Una CAL", "Una VLAN", "Un Token"], correcta: 0, justificacion: "Las CALs (User o Device) son requeridas por licenciamiento Microsoft."},
  {id: 96, tipo: "sm", pregunta: "¿Qué comandos de Linux se usan para monitorear CPU, Memoria y Disco?", opciones: ["top", "free -h", "df -h", "Get-Service"], correcta: [0, 1, 2], justificacion: "Get-Service es de PowerShell (Windows)."},
  {id: 97, tipo: "vf", pregunta: "El Mantenimiento Predictivo utiliza sensores y análisis de datos para anticipar fallas.", correcta: true, justificacion: "A diferencia del Preventivo (por tiempo) o Correctivo (tras la falla)."},
  {id: 98, tipo: "om", pregunta: "¿Qué política garantiza que la empresa pueda seguir operando tras un desastre?", opciones: ["AUP", "BCDR", "MFA"], correcta: 1, justificacion: "Business Continuity and Disaster Recovery."},
  {id: 99, tipo: "escenario", pregunta: "Un administrador necesita ver los últimos 10 errores de seguridad en el registro de eventos de Windows. ¿Qué cmdlet usa?", opciones: ["Get-EventLog -LogName Security -EntryType Error -Newest 10", "show log", "tail -f"], correcta: 0, justificacion: "Get-EventLog es el cmdlet nativo de PowerShell."},
  {id: 100, tipo: "vf", pregunta: "En una DMZ se ubican los servidores internos de bases de datos financieras para máxima seguridad.", correcta: false, justificacion: "En la DMZ van servidores públicos. Las BD financieras van en la Intranet."}
